module sram_cell (  
    input wire [15:0] data_in,  
    input wire [3:0] addr,  
    input wire we,  
    input wire ce,  
    output reg [15:0] data_out  
);  
    reg [15:0] sram_storage [15:0];  

    always @(posedge ce) begin  
        if (we)  
            sram_storage[addr] <= data_in;  
        else  
            data_out <= sram_storage[addr];  
    end  
endmodule
